#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding kinesiology-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    occupation:string! \
    sport_or_activity:string! \
    activity_level:string! \
    dominant_side:string! \
    contact_phone:string! \
    contact_email:string! \
    --htmx

cargo loco generate scaffold assessment_referral_information \
    assessment:references \
    referring_clinician:string! \
    referring_organisation:string! \
    referral_date:date \
    referral_reason:text! \
    previous_fms_assessment:string! \
    previous_fms_date:date \
    previous_fms_score:int \
    --htmx

cargo loco generate scaffold assessment_movement_history \
    assessment:references \
    current_pain:string! \
    pain_location:text! \
    pain_severity:int \
    pain_duration:string! \
    previous_injuries:text! \
    previous_surgeries:text! \
    chronic_conditions:text! \
    movement_limitations:text! \
    exercise_frequency:string! \
    exercise_type:text! \
    --htmx

cargo loco generate scaffold assessment_deep_squat \
    assessment:references \
    raw_score:int \
    pain_noted:string! \
    clearing_test_pain:string! \
    final_score:int \
    upper_torso_alignment:text! \
    femur_below_horizontal:string! \
    knees_over_feet:string! \
    heels_on_floor:string! \
    dowel_overhead:string! \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold assessment_hurdle_step \
    assessment:references \
    left_raw_score:int \
    right_raw_score:int \
    pain_noted_left:string! \
    pain_noted_right:string! \
    final_score:int \
    hip_knee_ankle_alignment_left:text! \
    hip_knee_ankle_alignment_right:text! \
    stance_leg_stable:string! \
    dowel_position_maintained:string! \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold assessment_in_line_lunge \
    assessment:references \
    left_raw_score:int \
    right_raw_score:int \
    pain_noted_left:string! \
    pain_noted_right:string! \
    final_score:int \
    dowel_contact_maintained:string! \
    torso_remains_upright:string! \
    knee_touches_board:string! \
    foot_alignment_maintained:string! \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold assessment_shoulder_mobility \
    assessment:references \
    left_raw_score:int \
    right_raw_score:int \
    pain_noted_left:string! \
    pain_noted_right:string! \
    clearing_test_pain_left:string! \
    clearing_test_pain_right:string! \
    final_score:int \
    hand_distance_cm:double \
    hand_span_length_cm:double \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold assessment_active_straight_leg_raise \
    assessment:references \
    left_raw_score:int \
    right_raw_score:int \
    pain_noted_left:string! \
    pain_noted_right:string! \
    final_score:int \
    malleolus_position_left:string! \
    malleolus_position_right:string! \
    opposite_leg_remains_flat:string! \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold assessment_trunk_stability_push_up \
    assessment:references \
    raw_score:int \
    pain_noted:string! \
    clearing_test_pain:string! \
    final_score:int \
    hand_position:string! \
    body_lifts_as_unit:string! \
    spine_sag_noted:string! \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold assessment_rotary_stability \
    assessment:references \
    left_raw_score:int \
    right_raw_score:int \
    pain_noted_left:string! \
    pain_noted_right:string! \
    clearing_test_pain:string! \
    final_score:int \
    unilateral_pattern_achieved:string! \
    diagonal_pattern_achieved:string! \
    trunk_rotation_noted:string! \
    clinician_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    total_fms_score:int! \
    risk_category:string! \
    asymmetry_count:int! \
    pain_count:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
